fixed_code:
fn main() {
    use std::fs::File;
    use std::io::{self, BufRead, BufReader};

    let f = File::open("example.txt").unwrap();
    let reader = BufReader::new(f);

    for line in reader.lines() {
        println!("{}", line.unwrap());
    }
}

